import React from "react";

const Registry = () => (
  <section id="registry" className="card">
    <h3>Registry</h3>
    <p>Your blessings are our greatest gift. If you wish to share a token of love, 
       please visit our registry or leave your wishes below.</p>
    <a href="https://docs.google.com/forms/d/e/1FAIpQLSfTZrW_36kcw88s84lb4SDZU0gA5a9Ql-IdMOiREAXwMxO-lw/viewform?usp=publish-editor" 
       target="_blank" rel="noreferrer" className="rsvp-btn">Leave Your Blessings</a>
  </section>
);

export default Registry;
